**完整題目**：給定兩個字串，回傳它們的最長公共子序列長度。

**線索**：題目能拆成前綴、位置或選擇序列，且不同路徑會到達相同子問題；需要把影響未來的資訊寫成狀態。

```cpp
class Solution {
 public:
  // 經典 LCS：dp[i][j] 表示 a[0..i-1] 與 b[0..j-1] 的最長公共子序列長度
  int longestCommonSubsequence(string a, string b) {
    int m = a.size(), n = b.size();
    vector<vector<int>> dp(m + 1, vector<int>(n + 1));  // 多一行一列作為邊界
    for (int i = 1; i <= m; ++i) {
      for (int j = 1; j <= n; ++j) {
        if (a[i - 1] == b[j - 1]) {
          dp[i][j] = dp[i - 1][j - 1] + 1;  // 字元吻合，LCS 延長 1
        } else {
          dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);  // 跳過 a[i] 或 b[j]
        }
      }
    }
    return dp[m][n];
  }
